13	/// <summary>
14	/// A user defined generic mapping method,
15	/// which can have a generic source parameter,
16	/// a generic target parameter or both.
17	/// Similar to <see cref="UserDefinedNewInstanceRuntimeTargetTypeParameterMapping"/>.
18	/// </summary>
19	public class UserDefinedNewInstanceGenericTypeMapping(
20	    IMethodSymbol method,
21	    MappingMethodParameters parameters,
22	    ITypeSymbol targetType,
23	    bool enableReferenceHandling,
24	    NullFallbackValue? nullArm,
25	    ITypeSymbol objectType
26	)
27	    : UserDefinedNewInstanceRuntimeTargetTypeMapping(
28	        method,
29	        parameters.Source,
30	        parameters.ReferenceHandler,
31	        targetType,
32	        enableReferenceHandling,
33	        nullArm,
34	        objectType
35	    )
36	{
37	    public override MethodDeclarationSyntax BuildMethod(SourceEmitterContext ctx)
38	    {
39	        var methodSyntax = (MethodDeclarationSyntax)Method.DeclaringSyntaxReferences.First().GetSyntax();
40	        return base.BuildMethod(ctx)
41	            .WithTypeParameterList(methodSyntax.TypeParameterList)
42	            .WithConstraintClauses(List(GetTypeParameterConstraintClauses()));
43	    }
44	
45	    protected override ExpressionSyntax BuildTargetType()
46	    {
47	        // typeof(<ReturnType>)
48	        return TypeOfExpression(FullyQualifiedIdentifier(Method.ReturnType.NonNullable()));
49	    }
50	
51	    protected virtual IEnumerable<TypeParameterConstraintClauseSyntax> GetTypeParameterConstraintClauses()
52	    {
53	        foreach (var tp in Method.TypeParameters)
54	        {
55	            var constraints = new List<TypeParameterConstraintSyntax>();
56	
57	            if (tp.HasUnmanagedTypeConstraint)
58	            {
59	                constraints.Add(TypeConstraint(IdentifierName("unmanaged")).AddLeadingSpace());
60	            }
61	            else if (tp.HasValueTypeConstraint)
62	            {
63	                constraints.Add(ClassOrStructConstraint(SyntaxKind.StructConstraint).AddLeadingSpace());
64	            }
65	            else if (tp.HasNotNullConstraint)
66	            {
67	                constraints.Add(TypeConstraint(IdentifierName("notnull")).AddLeadingSpace());
68	            }
69	            else if (tp.HasReferenceTypeConstraint)
70	            {
71	                constraints.Add(ClassOrStructConstraint(SyntaxKind.ClassConstraint).AddLeadingSpace());
72	            }
73	
74	            foreach (var c in tp.ConstraintTypes)
75	            {
76	                constraints.Add(TypeConstraint(FullyQualifiedIdentifier(c)).AddLeadingSpace());
77	            }
78	
79	            if (tp.HasConstructorConstraint)
80	            {
81	                constraints.Add(ConstructorConstraint().AddLeadingSpace());
82	            }
83	
84	            if (!constraints.Any())
85	            {
86	                continue;
87	            }
88	
89	            yield return TypeParameterConstraintClause(
90	                    IdentifierName(tp.Name).AddLeadingSpace().AddTrailingSpace(),
91	                    SeparatedList(constraints)
92	                )
93	                .AddLeadingSpace();
94	        }
95	    }
96	
97	    protected override ExpressionSyntax? BuildSwitchArmWhenClause(ExpressionSyntax targetType, RuntimeTargetTypeMapping mapping)
98	    {
99	        return mapping.IsAssignableToMethodTargetType ? null : base.BuildSwitchArmWhenClause(targetType, mapping);
100	    }
101	}
