8	namespace Riok.Mapperly.Descriptors;
9	
10	public class MappingCollection
11	{
12	    /// <summary>
13	    /// A list of all method mappings in order of registration/discovery.
14	    /// This is kept outside of <see cref="MappingCollectionInstance{T,TUserMapping}"/>
15	    /// to keep track of the registration order and generate the members in the same order as they are registered
16	    /// (the user defined order).
17	    /// </summary>
18	    private readonly List<MethodMapping> _methodMappings = [];
19	
20	    /// <summary>
21	    /// A list of all user mappings.
22	    /// Does only include mappings which are discovered during the initial user mapping discovery.
23	    /// If a mapping is discovered afterwards (eg. by a name reference) it is not added to this collection.
24	    /// This is kept outside of <see cref="MappingCollectionInstance{T,TUserMapping}"/>
25	    /// to keep track of the registration order and generate the members in the same order as they are registered.
26	    /// </summary>
27	    private readonly List<IUserMapping> _userMappings = [];
28	
29	    /// <summary>
30	    /// Queue of mappings which don't have the body built yet
31	    /// </summary>
32	    private readonly Queue<(IMapping, MappingBuilderContext)> _mappingsToBuildBody = new();
33	
34	    /// <summary>
35	    /// All new instance mappings
36	    /// </summary>
37	    private readonly MappingCollectionInstance<INewInstanceMapping, INewInstanceUserMapping> _newInstanceMappings = new();
38	
39	    /// <summary>
40	    /// All existing target mappings
41	    /// </summary>
42	    private readonly MappingCollectionInstance<IExistingTargetMapping, IExistingTargetUserMapping> _existingTargetMappings = new();
43	
44	    /// <inheritdoc cref="_methodMappings"/>
45	    public IReadOnlyCollection<MethodMapping> MethodMappings => _methodMappings;
46	
47	    /// <inheritdoc cref="_userMappings"/>
48	    public IReadOnlyCollection<IUserMapping> UserMappings => _userMappings;
49	
50	    /// <inheritdoc cref="MappingCollectionInstance{INewInstanceMapping, INewInstanceUserMapping}.DefaultMappings"/>
51	    public IReadOnlyDictionary<TypeMappingKey, INewInstanceMapping> NewInstanceMappings => _newInstanceMappings.DefaultMappings;
52	
53	    /// <summary>
54	    /// All existing target user mappings registered by their methods.
55	    /// </summary>
56	    public IEnumerable<IExistingTargetUserMapping> ExistingTargetUserMappings => _existingTargetMappings.UserMappings;
57	
58	    /// <inheritdoc cref="MappingCollectionInstance{T,TUserMapping}.UsedDuplicatedNonDefaultNonReferencedUserMappings"/>
59	    public IEnumerable<IUserMapping> UsedDuplicatedNonDefaultNonReferencedUserMappings =>
60	        Enumerable
61	            .Empty<IUserMapping>()
62	            .Concat(_newInstanceMappings.UsedDuplicatedNonDefaultNonReferencedUserMappings)
63	            .Concat(_existingTargetMappings.UsedDuplicatedNonDefaultNonReferencedUserMappings);
64	
65	    public INewInstanceMapping? FindNewInstanceMapping(TypeMappingKey mappingKey, ParameterScope? scope = null) =>
66	        _newInstanceMappings.Find(mappingKey, scope);
67	
68	    public INewInstanceUserMapping? FindNewInstanceUserMapping(IMethodSymbol method) => _newInstanceMappings.FindUserMapping(method);
69	
70	    public INewInstanceMapping? FindNamedNewInstanceMapping(string name, out bool ambiguousName) =>
71	        _newInstanceMappings.FindNamed(name, out ambiguousName);
72	
73	    public IExistingTargetMapping? FindExistingInstanceMapping(TypeMappingKey mappingKey) => _existingTargetMappings.Find(mappingKey);
74	
75	    public IExistingTargetMapping? FindExistingInstanceNamedMapping(string name, out bool ambiguousName) =>
76	        _existingTargetMappings.FindNamed(name, out ambiguousName);
77	
78	    public IEnumerable<(IMapping, MappingBuilderContext)> DequeueMappingsToBuildBody() => _mappingsToBuildBody.DequeueAll();
79	
80	    public void EnqueueToBuildBody(ITypeMapping mapping, MappingBuilderContext ctx) => _mappingsToBuildBody.Enqueue((mapping, ctx));
81	
82	    public MappingCollectionAddResult AddUserMapping(IUserMapping userMapping, string? name)
83	    {
84	        _userMappings.Add(userMapping);
85	
86	        if (userMapping is MethodMapping methodMapping)
87	        {
88	            _methodMappings.Add(methodMapping);
89	        }
90	
91	        return userMapping switch
92	        {
93	            INewInstanceUserMapping newInstanceMapping => _newInstanceMappings.AddUserMapping(
94	                newInstanceMapping,
95	                userMapping.Default,
96	                name
97	            ),
98	            IExistingTargetUserMapping existingTargetMapping => _existingTargetMappings.AddUserMapping(
99	                existingTargetMapping,
100	                userMapping.Default,
101	                name
102	            ),
103	            _ => throw new ArgumentOutOfRangeException(nameof(userMapping), userMapping.GetType().FullName + " mappings are not supported"),
104	        };
105	    }
106	
107	    public MappingCollectionAddResult AddNewInstanceMapping(INewInstanceMapping mapping, TypeMappingConfiguration config)
108	    {
109	        if (mapping is MethodMapping methodMapping)
110	        {
111	            _methodMappings.Add(methodMapping);
112	        }
113	
114	        return _newInstanceMappings.TryAddAsDefault(mapping, config);
115	    }
116	
117	    public MappingCollectionAddResult AddExistingTargetMapping(IExistingTargetMapping mapping, TypeMappingConfiguration config)
118	    {
119	        if (mapping is MethodMapping methodMapping)
120	        {
121	            _methodMappings.Add(methodMapping);
122	        }
123	
124	        return _existingTargetMappings.TryAddAsDefault(mapping, config);
125	    }
126	
127	    public void AddNamedNewInstanceUserMappings(string name, IEnumerable<INewInstanceUserMapping> mappings)
128	    {
129	        foreach (var mapping in mappings)
130	        {
131	            AddNamedNewInstanceUserMapping(name, mapping);
132	        }
133	    }
134	
135	    public void AddNamedNewInstanceUserMapping(string name, INewInstanceUserMapping mapping)
136	    {
137	        Debug.Assert(
138	            mapping.Default != true,
139	            $"Cannot add a named mapping ({name}, {mapping.Method.Name}) after the initial discovery which is a default mapping"
140	        );
141	        _newInstanceMappings.AddNamedUserMapping(name, mapping);
142	    }
143	
144	    public void AddNamedExistingInstanceUserMappings(string name, IEnumerable<IExistingTargetUserMapping> mappings)
145	    {
146	        foreach (var mapping in mappings)
147	        {
148	            AddNamedExistingInstanceUserMapping(name, mapping);
149	        }
150	    }
151	
152	    public void AddNamedExistingInstanceUserMapping(string name, IExistingTargetUserMapping mapping)
153	    {
154	        Debug.Assert(
155	            mapping.Default != true,
156	            $"Cannot add a named mapping ({name}, {mapping.Method.Name}) after the initial discovery which is a default mapping"
157	        );
158	        _existingTargetMappings.AddNamedUserMapping(name, mapping);
159	    }
160	
161	    private class MappingCollectionInstance<T, TUserMapping>
162	        where T : ITypeMapping
163	        where TUserMapping : T, IUserMapping
164	    {
165	        /// <summary>
166	        /// Default mappings of each type pair + config.
167	        /// A default mappings is the mapping Mapperly should use to convert from one type to another.
168	        /// Contains mappings to build and already built mappings.
169	        /// </summary>
170	        private readonly Dictionary<TypeMappingKey, T> _defaultMappings = new();
171	
172	        /// <summary>
173	        /// Registered user mappings by their methods.
174	        /// </summary>
175	        private readonly Dictionary<IMethodSymbol, TUserMapping> _userMappingsByMethod = new(SymbolEqualityComparer.Default);
176	
177	        /// <summary>
178	        /// All user mappings registered in this instance, indexed by source/target type pair.
179	        /// Used as the canonical source for parameterized and diagnostic queries.
180	        /// </summary>
181	        private readonly ListDictionary<TypeMappingKey, TUserMapping> _userMappings = new();
182	
183	        /// <summary>
184	        /// Named mappings by their names.
185	        /// </summary>
186	        private readonly Dictionary<string, TUserMapping> _namedMappings = new();
187	
188	        /// <summary>
189	        /// Duplicated mapping names.
190	        /// </summary>
191	        private readonly HashSet<string> _duplicatedMappingNames = [];
192	
193	        /// <summary>
194	        /// All mapping type keys which for which an explicit default mapping is configured.
195	        /// </summary>
196	        private readonly HashSet<TypeMappingKey> _explicitDefaultMappingKeys = [];
197	
198	        /// <summary>
199	        /// All mapping keys for which <see cref="Find(TypeMappingKey, ParameterScope?)"/> was called and returned a non-null result.
200	        /// </summary>
201	        private readonly HashSet<TypeMappingKey> _usedMappingKeys = [];
202	
203	        /// <summary>
204	        /// All mappings for which <see cref="FindNamed"/> was called and returned a non-null result.
205	        /// </summary>
206	        private readonly HashSet<TUserMapping> _referencedNamedMappings = [];
207	
208	        /// <inheritdoc cref="_defaultMappings"/>
209	        public IReadOnlyDictionary<TypeMappingKey, T> DefaultMappings => _defaultMappings;
210	
211	        /// <summary>
212	        /// All registered user mappings.
213	        /// </summary>
214	        public IEnumerable<TUserMapping> UserMappings => _userMappingsByMethod.Values;
215	
216	        /// <summary>
217	        /// Returns user mappings that are duplicates (same type pair, no explicit default)
218	        /// for type-pairs which are actually in use and not referenced by name.
219	        /// Within each group, the first mapping (which won the _defaultMappings race) is excluded.
220	        /// </summary>
221	        public IEnumerable<TUserMapping> UsedDuplicatedNonDefaultNonReferencedUserMappings =>
222	            _userMappings
223	                .AsDictionary()
224	                .Where(g => _usedMappingKeys.Contains(g.Key) && !_explicitDefaultMappingKeys.Contains(g.Key))
225	                .Select(g => g.Value.Where(m => !m.IsExternal && !m.Default.HasValue))
226	                .Where(g => g.Skip(1).Any())
227	                .SelectMany(g => g.Skip(1))
228	                .Where(m => !_referencedNamedMappings.Contains(m));
229	
230	        public TUserMapping? FindUserMapping(IMethodSymbol method) => _userMappingsByMethod.GetValueOrDefault(method);
231	
232	        public T? Find(TypeMappingKey mappingKey, ParameterScope? scope = null)
233	        {
234	            if (scope is { IsEmpty: false })
235	                return FindByParameters(mappingKey, scope);
236	
237	            if (_defaultMappings.TryGetValue(mappingKey, out var mapping))
238	            {
239	                _usedMappingKeys.Add(mappingKey);
240	            }
241	
242	            return mapping;
243	        }
244	
245	        public T? FindNamed(string name, out bool ambiguousName)
246	        {
247	            ambiguousName = false;
248	            if (_namedMappings.TryGetValue(name, out var mapping))
249	            {
250	                ambiguousName = _duplicatedMappingNames.Contains(name);
251	                _referencedNamedMappings.Add(mapping);
252	            }
253	
254	            return mapping;
255	        }
256	
257	        private TUserMapping? FindByParameters(TypeMappingKey key, ParameterScope scope)
258	        {
259	            var candidates = _userMappings.GetOrEmpty(key).Where(m => m is IParameterizedMapping { AdditionalSourceParameters.Count: > 0 });
260	
261	            foreach (var mapping in candidates)
262	            {
263	                if (scope.TryUseParameters(mapping))
264	                    return mapping;
265	            }
266	
267	            return default;
268	        }
269	
270	        public void AddNamedUserMapping(string? name, TUserMapping mapping)
271	        {
272	            var isNewUserMappingMethod = _userMappingsByMethod.TryAdd(mapping.Method, mapping);
273	
274	            if (name == null)
275	                return;
276	
277	            if (_namedMappings.TryAdd(name, mapping))
278	                return;
279	
280	            // if the name is duplicated
281	            // and there is already another user mapping instance registered for the same method symbol,
282	            // this name is not considered duplicated as the mapping just got re-discovered
283	            if (isNewUserMappingMethod)
284	            {
285	                _duplicatedMappingNames.Add(name);
286	            }
287	        }
288	
289	        public MappingCollectionAddResult TryAddAsDefault(T mapping, TypeMappingConfiguration config)
290	        {
291	            var mappingKey = new TypeMappingKey(mapping, config);
292	            var result = _defaultMappings.TryAdd(mappingKey, mapping)
293	                ? MappingCollectionAddResult.Added
294	                : MappingCollectionAddResult.NotAddedDuplicated;
295	            AddAdditionalMappings(mapping, config);
296	            return result;
297	        }
298	
299	        public MappingCollectionAddResult AddUserMapping(TUserMapping mapping, bool? isDefault, string? name)
300	        {
301	            AddNamedUserMapping(name, mapping);
302	            _userMappings.Add(new TypeMappingKey(mapping), mapping);
303	
304	            return isDefault switch
305	            {
306	                // the mapping is not a default mapping.
307	                false => MappingCollectionAddResult.NotAddedIgnored,
308	
309	                // if a default mapping was already added for this type-pair
310	                // ignore the current one and return duplicated
311	                // otherwise overwrite the existing with the new default one.
312	                true => AddDefaultUserMapping(mapping),
313	
314	                // no default value specified
315	                // add it if none exists yet
316	                null => TryAddAsDefault(mapping, TypeMappingConfiguration.Default),
317	            };
318	        }
319	
320	        private MappingCollectionAddResult AddDefaultUserMapping(T mapping)
321	        {
322	            var mappingKey = new TypeMappingKey(mapping);
323	            if (!_explicitDefaultMappingKeys.Add(mappingKey))
324	                return MappingCollectionAddResult.NotAddedDuplicated;
325	
326	            _defaultMappings[mappingKey] = mapping;
327	            AddAdditionalMappings(mapping, TypeMappingConfiguration.Default);
328	            return MappingCollectionAddResult.Added;
329	        }
330	
331	        private void AddAdditionalMappings(T mapping, TypeMappingConfiguration config)
332	        {
333	            foreach (var additionalKey in mapping.BuildAdditionalMappingKeys(config))
334	            {
335	                _defaultMappings.TryAdd(additionalKey, mapping);
336	            }
337	        }
338	    }
339	}
