1	using Microsoft.CodeAnalysis;
2	using Microsoft.CodeAnalysis.CSharp.Syntax;
3	using Riok.Mapperly.Abstractions.ReferenceHandling;
4	using Riok.Mapperly.Emit.Syntax;
5	using Riok.Mapperly.Helpers;
6	using Riok.Mapperly.Symbols;
7	using static Microsoft.CodeAnalysis.CSharp.SyntaxFactory;
8	using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;
9	
10	namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;
11	
12	/// <summary>
13	/// A mapping which has a <see cref="Type"/> as a second parameter describing the target type of the mapping.
14	/// Generates a switch expression based on the mapping types.
15	/// </summary>
16	public abstract class UserDefinedNewInstanceRuntimeTargetTypeMapping(
17	    IMethodSymbol method,
18	    MethodParameter sourceParameter,
19	    MethodParameter? referenceHandlerParameter,
20	    ITypeSymbol targetType,
21	    bool enableReferenceHandling,
22	    NullFallbackValue? nullArm,
23	    ITypeSymbol objectType
24	) : NewInstanceMethodMapping(method, sourceParameter, referenceHandlerParameter, targetType), INewInstanceUserMapping
25	{
26	    private const string IsAssignableFromMethodName = nameof(Type.IsAssignableFrom);
27	    private const string GetTypeMethodName = nameof(GetType);
28	
29	    private readonly List<RuntimeTargetTypeMapping> _mappings = [];
30	
31	    public new IMethodSymbol Method { get; } = method;
32	
33	    /// <summary>
34	    /// Always false, as this cannot be called by other mappings,
35	    /// this can never be the default.
36	    /// </summary>
37	    public bool? Default => false;
38	
39	    public bool IsExternal => false;
40	
41	    /// <summary>
42	    /// The reference handling is enabled but is only internal to this method.
43	    /// No reference handler parameter is passed.
44	    /// </summary>
45	    private bool InternalReferenceHandlingEnabled => enableReferenceHandling && ReferenceHandlerParameter == null;
46	
47	    public void AddMappings(IEnumerable<RuntimeTargetTypeMapping> mappings) => _mappings.AddRange(mappings);
48	
49	    public override IEnumerable<StatementSyntax> BuildBody(TypeMappingBuildContext ctx)
50	    {
51	        // if reference handling is enabled and no reference handler parameter is declared
52	        // a new reference handler is instantiated and used.
53	        if (InternalReferenceHandlingEnabled)
54	        {
55	            // var refHandler = new RefHandler();
56	            var referenceHandlerName = ctx.NameBuilder.New(DefaultReferenceHandlerParameterName);
57	            var createRefHandler = ctx.SyntaxFactory.CreateInstance<PreserveReferenceHandler>();
58	            yield return ctx.SyntaxFactory.DeclareLocalVariable(referenceHandlerName, createRefHandler);
59	
60	            ctx = ctx.WithRefHandler(referenceHandlerName);
61	        }
62	
63	        var targetTypeExpr = BuildTargetType();
64	
65	        // _ => throw new ArgumentException(msg, nameof(ctx.Source)),
66	        var sourceType = ctx.SyntaxFactory.Invocation(MemberAccess(ctx.Source, GetTypeMethodName));
67	        var fallbackArm = SwitchArm(
68	            DiscardPattern(),
69	            ThrowArgumentExpression(
70	                InterpolatedString($"Cannot map {sourceType} to {targetTypeExpr} as there is no known type mapping"),
71	                ctx.Source
72	            )
73	        );
74	
75	        // source switch { A x when targetType.IsAssignableFrom(typeof(ADto)) => MapToADto(x), B x when targetType.IsAssignableFrom(typeof(BDto)) => MapToBDto(x) }
76	        var (typeArmContext, typeArmVariableName) = ctx.WithNewScopedSource();
77	        var arms = _mappings.Select(x => BuildSwitchArm(typeArmContext, typeArmVariableName, x, targetTypeExpr));
78	
79	        // null => default / throw
80	        if (nullArm.HasValue)
81	        {
82	            arms = arms.Append(SwitchArm(ConstantPattern(NullLiteral()), NullSubstitute(TargetType, ctx.Source, nullArm.Value)));
83	        }
84	
85	        arms = arms.Append(fallbackArm);
86	        var switchExpression = ctx.SyntaxFactory.Switch(ctx.Source, arms);
87	        yield return ctx.SyntaxFactory.Return(switchExpression);
88	    }
89	
90	    protected abstract ExpressionSyntax BuildTargetType();
91	
92	    protected virtual ExpressionSyntax? BuildSwitchArmWhenClause(ExpressionSyntax runtimeTargetType, RuntimeTargetTypeMapping mapping)
93	    {
94	        // targetType.IsAssignableFrom(typeof(ADto))
95	        return InvocationWithoutIndention(
96	            MemberAccess(runtimeTargetType, IsAssignableFromMethodName),
97	            TypeOfExpression(FullyQualifiedIdentifier(mapping.Mapping.TargetType.NonNullable()))
98	        );
99	    }
100	
101	    internal override void EnableReferenceHandling(INamedTypeSymbol iReferenceHandlerType)
102	    {
103	        // the parameters of user defined methods should not be manipulated
104	    }
105	
106	    private SwitchExpressionArmSyntax BuildSwitchArm(
107	        TypeMappingBuildContext typeArmContext,
108	        string typeArmVariableName,
109	        RuntimeTargetTypeMapping mapping,
110	        ExpressionSyntax targetType
111	    )
112	    {
113	        // A x when targetType.IsAssignableFrom(typeof(ADto)) => MapToADto(x),
114	        var declaration = DeclarationPattern(
115	            FullyQualifiedIdentifier(mapping.Mapping.SourceType.NonNullable()).AddTrailingSpace(),
