1	using Microsoft.CodeAnalysis;
2	using Riok.Mapperly.Abstractions;
3	using Riok.Mapperly.Descriptors.Mappings;
4	using Riok.Mapperly.Descriptors.Mappings.ExistingTarget;
5	using Riok.Mapperly.Diagnostics;
6	using Riok.Mapperly.Helpers;
7	
8	namespace Riok.Mapperly.Descriptors.MappingBuilders;
9	
10	public static class NewInstanceObjectMemberMappingBuilder
11	{
12	    public static INewInstanceMapping? TryBuildMapping(MappingBuilderContext ctx)
13	    {
14	        if (ctx.Target.SpecialType != SpecialType.None)
15	            return null;
16	
17	        if (ctx.Source.IsDelegate() || ctx.Target.IsDelegate())
18	            return null;
19	
20	        if (ctx.InstanceConstructors.TryBuildObjectFactory(ctx.Source, ctx.Target, out var constructor))
21	        {
22	            return new NewInstanceObjectMemberMethodMapping(
23	                ctx.Source,
24	                ctx.Target.NonNullable(),
25	                ctx.Configuration.Mapper.UseReferenceHandling
26	            )
27	            {
28	                Constructor = constructor,
29	            };
30	        }
31	
32	        if (ctx.Source.IsEnum() || ctx.Target.IsEnum())
33	            return null;
34	
35	        if (!ctx.SymbolAccessor.HasAnyAccessibleConstructor(ctx.Target))
36	        {
37	            ctx.ReportDiagnostic(DiagnosticDescriptors.NoConstructorFound, ctx.Target);
38	            return new UnimplementedMapping(ctx.Source, ctx.Target);
39	        }
40	
41	        if (ctx.Target.IsTupleType)
42	            return BuildTupleMapping(ctx);
43	
44	        // inline expressions don't support method property mappings
45	        // and can only map to properties via object initializers.
46	        return ctx.IsExpression
47	            ? new NewInstanceObjectMemberMapping(ctx.Source, ctx.Target.NonNullable())
48	            : new NewInstanceObjectMemberMethodMapping(ctx.Source, ctx.Target.NonNullable(), ctx.Configuration.Mapper.UseReferenceHandling);
49	    }
50	
51	    public static IExistingTargetMapping? TryBuildExistingTargetMapping(MappingBuilderContext ctx)
52	    {
53	        if (ctx.Target.SpecialType != SpecialType.None || ctx.Source.SpecialType != SpecialType.None)
54	            return null;
55	
56	        if (ctx.Target.IsImmutable())
57	            return null;
58	
59	        if (ctx.Source.IsEnum() || ctx.Target.IsEnum())
60	            return null;
61	
62	        return new ObjectMemberExistingTargetMapping(ctx.Source, ctx.Target);
63	    }
64	
65	    private static INewInstanceMapping? BuildTupleMapping(MappingBuilderContext ctx)
66	    {
67	        if (!ctx.IsConversionEnabled(MappingConversionType.Tuple))
68	            return null;
69	
70	        // inline expressions don't support tuple expressions so ValueTuple is used instead
71	        if (ctx.IsExpression)
72	        {
73	            return new NewValueTupleConstructorMapping(ctx.Source, ctx.Target);
74	        }
75	
76	        var expectedArgumentCount = (ctx.Target as INamedTypeSymbol)!.TupleElements.Length;
77	        return new NewValueTupleExpressionMapping(ctx.Source, ctx.Target, expectedArgumentCount);
78	    }
79	}
