9	
10	internal static class UserMappingMethodParameterExtractor
11	{
12	    public static bool BuildParameters(
13	        SimpleMappingBuilderContext ctx,
14	        IMethodSymbol method,
15	        [NotNullWhen(true)] out MappingMethodParameters? parameters
16	    )
17	    {
18	        var refHandlerParameter = FindReferenceHandlerParameter(ctx, method);
19	        var refHandlerParameterOrdinal = refHandlerParameter?.Ordinal ?? -1;
20	
21	        var sourceParameter = FindSourceParameter(ctx, method, refHandlerParameter);
22	        if (!sourceParameter.HasValue)
23	        {
24	            parameters = null;
25	            return false;
26	        }
27	
28	        // If the method returns void, a target parameter is required
29	        // if the method doesn't return void, a target parameter is not allowed.
30	        MethodParameter? targetParameter = null;
31	        if (method.ReturnsVoid)
32	        {
33	            targetParameter = FindTargetParameter(ctx, method, sourceParameter.Value, refHandlerParameter);
34	            if (!targetParameter.HasValue)
35	            {
36	                parameters = null;
37	                return false;
38	            }
39	        }
40	
41	        var targetParameterOrdinal = targetParameter?.Ordinal ?? -1;
42	        var additionalParameterSymbols = method
43	            .Parameters.Where(p =>
44	                p.Ordinal != sourceParameter.Value.Ordinal && p.Ordinal != targetParameterOrdinal && p.Ordinal != refHandlerParameterOrdinal
45	            )
46	            .ToList();
47	        // additional parameters should not be attributed as target or ref handler
48	        var hasInvalidAdditionalParameter = additionalParameterSymbols.Exists(p =>
49	            p.Type.TypeKind is TypeKind.TypeParameter or TypeKind.Error
50	            || ctx.SymbolAccessor.HasAttribute<ReferenceHandlerAttribute>(p)
51	            || ctx.SymbolAccessor.HasAttribute<MappingTargetAttribute>(p)
52	        );
53	        if (hasInvalidAdditionalParameter)
54	        {
55	            parameters = null;
56	            return false;
57	        }
58	
59	        var additionalParameters = additionalParameterSymbols.Select(p => ctx.SymbolAccessor.WrapMethodParameter(p)).ToList();
60	
61	        // detect and deduplicate case-insensitive duplicate additional parameter names (e.g., int UserId, int userId)
62	        var parameterGroups = additionalParameters.ToLookup(p => p.NormalizedName, StringComparer.OrdinalIgnoreCase);
