115	    private ITypeSymbol? InferAndCheckTypes(InferState state, INamedTypeSymbol param, ITypeSymbol arg)
116	    {
117	        if (!arg.ExtendsOrImplementsGeneric(param.OriginalDefinition, out var genericTypedArgument))
118	            return null;
