120	        var inferredParamTypeArgs = new ITypeSymbol[param.TypeArguments.Length];
121	        var inferredParamsHasChanges = false;
122	        for (var i = 0; i < param.TypeArguments.Length; i++)
123	        {
124	            var paramTypeArg = param.TypeArguments[i];
125	            var argTypeArg = genericTypedArgument.TypeArguments[i];
126	            var inferredParamTypeArg = InferAndCheckTypes(state, paramTypeArg, argTypeArg);
127	            if (inferredParamTypeArg == null)
