1	using System.Collections.Immutable;
2	using Microsoft.CodeAnalysis;
3	using Riok.Mapperly.Abstractions;
4	using Riok.Mapperly.Abstractions.ReferenceHandling;
5	using Riok.Mapperly.Configuration;
6	using Riok.Mapperly.Descriptors.Constructors;
7	using Riok.Mapperly.Descriptors.ExternalMappings;
8	using Riok.Mapperly.Descriptors.FormatProviders;
9	using Riok.Mapperly.Descriptors.MappingBodyBuilders;
10	using Riok.Mapperly.Descriptors.MappingBuilders;
11	using Riok.Mapperly.Descriptors.Mappings.UserMappings;
12	using Riok.Mapperly.Descriptors.ObjectFactories;
13	using Riok.Mapperly.Descriptors.UnsafeAccess;
14	using Riok.Mapperly.Diagnostics;
15	using Riok.Mapperly.Helpers;
16	using Riok.Mapperly.Symbols;
17	
18	namespace Riok.Mapperly.Descriptors;
19	
20	public class DescriptorBuilder
21	{
22	    private readonly MapperDescriptor _mapperDescriptor;
23	    private readonly SymbolAccessor _symbolAccessor;
24	    private readonly ImmutableArray<UseStaticMapperConfiguration> _assemblyScopedStaticMappers;
25	
26	    private readonly MappingCollection _mappings = new();
27	    private readonly InlinedExpressionMappingCollection _inlineMappings = new();
28	
29	    private readonly MethodNameBuilder _methodNameBuilder = new();
30	    private readonly MappingBodyBuilder _mappingBodyBuilder;
31	    private readonly SimpleMappingBuilderContext _builderContext;
32	    private readonly DiagnosticCollection _diagnostics;
33	    private readonly UnsafeAccessorContext _unsafeAccessorContext;
34	    private readonly AttributeDataAccessor _attributeAccessor;
35	
36	    public DescriptorBuilder(
37	        CompilationContext compilationContext,
38	        MapperDeclaration mapperDeclaration,
39	        SymbolAccessor symbolAccessor,
40	        AttributeDataAccessor attributeDataAccessor,
41	        MapperConfiguration defaultMapperConfiguration,
42	        ImmutableArray<UseStaticMapperConfiguration> assemblyScopedStaticMappers
43	    )
44	    {
45	        var supportedFeatures = SupportedFeatures.Build(compilationContext.Types, symbolAccessor, compilationContext.ParseLanguageVersion);
46	        _mapperDescriptor = new MapperDescriptor(mapperDeclaration, _methodNameBuilder, supportedFeatures);
47	        _symbolAccessor = symbolAccessor;
48	        _attributeAccessor = attributeDataAccessor;
49	        _assemblyScopedStaticMappers = assemblyScopedStaticMappers;
50	        _mappingBodyBuilder = new MappingBodyBuilder(_mappings);
51	        _unsafeAccessorContext = new UnsafeAccessorContext(_methodNameBuilder, symbolAccessor);
52	        _diagnostics = new DiagnosticCollection(mapperDeclaration.Syntax.GetLocation());
53	
54	        var genericTypeChecker = new GenericTypeChecker(_symbolAccessor, compilationContext.Types);
55	        var configurationReader = new MapperConfigurationReader(
56	            _attributeAccessor,
57	            _mappings,
58	            genericTypeChecker,
59	            _diagnostics,
60	            compilationContext.Types,
61	            mapperDeclaration.Symbol,
62	            defaultMapperConfiguration,
63	            supportedFeatures
64	        );
65	
66	        _builderContext = new SimpleMappingBuilderContext(
67	            compilationContext,
68	            mapperDeclaration,
69	            configurationReader,
70	            _symbolAccessor,
71	            genericTypeChecker,
72	            _attributeAccessor,
73	            _unsafeAccessorContext,
74	            _diagnostics,
75	            new MappingBuilder(_mappings, mapperDeclaration),
76	            new ExistingTargetMappingBuilder(_mappings, mapperDeclaration),
77	            _inlineMappings,
78	            mapperDeclaration.Syntax.GetLocation()
79	        );
80	    }
81	
82	    public (MapperDescriptor descriptor, DiagnosticCollection diagnostics) Build(CancellationToken cancellationToken)
83	    {
84	        ConfigureMemberVisibility();
85	        ReserveMethodNames();
86	        ExtractUserMappings();
87	        ExtractExternalNamedMappings();
88	
89	        // ExtractObjectFactories needs to be called after ExtractUserMappings due to configuring mapperDescriptor.Static
90	        var objectFactories = ExtractObjectFactories();
91	        var constructorFactory = new InstanceConstructorFactory(objectFactories, _symbolAccessor, _unsafeAccessorContext);
92	        var formatProviders = ExtractFormatProviders();
93	        EnqueueUserMappings(constructorFactory, formatProviders);
94	        ExtractExternalMappings();
95	        _mappingBodyBuilder.BuildMappingBodies(cancellationToken);
96	        AddUserMappingDiagnostics();
97	        BuildMappingMethodNames();
98	        BuildReferenceHandlingParameters();
99	        AddMappingsToDescriptor();
100	        AddAccessorsToDescriptor();
101	        return (_mapperDescriptor, _diagnostics);
102	    }
103	
104	    /// <summary>
105	    /// Sets the member and constructor visibility filter on the <see cref="_symbolAccessor"/> after validation.
106	    /// If <see cref="MemberVisibility.Accessible"/> is not set and the compilation does not have UnsafeAccessors,
107	    /// emit a diagnostic and update the <see cref="MemberVisibility"/> to include <see cref="MemberVisibility.Accessible"/>.
108	    /// </summary>
109	    private void ConfigureMemberVisibility()
110	    {
111	        var includedMembers = _builderContext.Configuration.Mapper.IncludedMembers;
112	        var includedConstructors = _builderContext.Configuration.Mapper.IncludedConstructors;
113	
114	        if (_mapperDescriptor.SupportedFeatures.UnsafeAccessors)
115	        {
116	            _symbolAccessor.SetMemberVisibility(includedMembers);
117	            _symbolAccessor.SetConstructorVisibility(includedConstructors);
118	            return;
119	        }
120	
121	        if (includedMembers.HasFlag(MemberVisibility.Accessible) && includedConstructors.HasFlag(MemberVisibility.Accessible))
122	        {
123	            return;
124	        }
125	
126	        _diagnostics.ReportDiagnostic(DiagnosticDescriptors.UnsafeAccessorNotAvailable);
127	        _symbolAccessor.SetMemberVisibility(includedMembers | MemberVisibility.Accessible);
128	        _symbolAccessor.SetConstructorVisibility(includedConstructors | MemberVisibility.Accessible);
129	    }
130	
131	    private void ReserveMethodNames()
132	    {
133	        foreach (var methodSymbol in _symbolAccessor.GetAllMembers(_mapperDescriptor.Symbol))
134	        {
135	            _methodNameBuilder.Reserve(methodSymbol.Name);
136	        }
137	    }
138	
139	    private void ExtractUserMappings()
140	    {
141	        _mapperDescriptor.Static = _mapperDescriptor.Symbol.IsStatic;
142	        IMethodSymbol? firstNonStaticUserMapping = null;
143	
144	        foreach (var userMapping in UserMethodMappingExtractor.ExtractUserMappings(_builderContext, _mapperDescriptor.Symbol))
145	        {
146	            // if a user defined mapping method is static, all of them need to be static to avoid confusion for mapping method resolution
147	            // however, user implemented mapping methods are allowed to be static in a non-static context.
148	            // Therefore, we are only interested in partial method definitions here.
149	            if (userMapping.Method is { IsStatic: true, IsPartialDefinition: true })
150	            {
151	                _mapperDescriptor.Static = true;
152	            }
153	            else if (firstNonStaticUserMapping == null && !userMapping.Method.IsStatic)
154	            {
155	                firstNonStaticUserMapping = userMapping.Method;
156	            }
157	
158	            var name = _attributeAccessor.GetMappingName(userMapping.Method);
159	            AddUserMapping(userMapping, ignoreDuplicates: false, name);
160	        }
161	
162	        if (_mapperDescriptor.Static && firstNonStaticUserMapping is not null)
163	        {
164	            _diagnostics.ReportDiagnostic(
165	                DiagnosticDescriptors.MixingStaticPartialWithInstanceMethod,
166	                firstNonStaticUserMapping,
167	                _mapperDescriptor.Symbol.ToDisplayString()
168	            );
169	        }
170	    }
171	
172	    private ObjectFactoryCollection ExtractObjectFactories()
173	    {
174	        return ObjectFactoryBuilder.ExtractObjectFactories(_builderContext, _mapperDescriptor.Symbol, _mapperDescriptor.Static);
175	    }
176	
177	    private void EnqueueUserMappings(InstanceConstructorFactory constructorFactory, FormatProviderCollection formatProviders)
178	    {
179	        foreach (var userMapping in _mappings.UserMappings)
180	        {
181	            var ctx = new MappingBuilderContext(
182	                _builderContext,
183	                constructorFactory,
184	                formatProviders,
185	                userMapping,
186	                new TypeMappingKey(userMapping.SourceType, userMapping.TargetType)
187	            );
188	
189	            _mappings.EnqueueToBuildBody(userMapping, ctx);
190	        }
191	    }
192	
193	    private void ExtractExternalMappings()
194	    {
195	        foreach (
196	            var externalMapping in ExternalMappingsExtractor.ExtractExternalMappings(
197	                _assemblyScopedStaticMappers,
198	                _builderContext,
199	                _mapperDescriptor.Symbol
200	            )
201	        )
202	        {
203	            AddUserMapping(externalMapping, ignoreDuplicates: true);
204	        }
205	    }
206	
207	    private void ExtractExternalNamedMappings()
208	    {
209	        foreach (var (name, mapping) in ExternalMappingsExtractor.ExtractExternalNamedMappings(_builderContext, _mapperDescriptor.Symbol))
210	        {
211	            AddUserMapping(mapping, ignoreDuplicates: true, name);
212	        }
213	    }
214	
215	    private FormatProviderCollection ExtractFormatProviders()
216	    {
217	        return FormatProviderBuilder.ExtractFormatProviders(_builderContext, _mapperDescriptor.Symbol, _mapperDescriptor.Static);
218	    }
219	
220	    private void BuildMappingMethodNames()
221	    {
222	        foreach (var methodMapping in _mappings.MethodMappings)
223	        {
224	            methodMapping.SetMethodNameIfNeeded(_methodNameBuilder.Build);
225	        }
226	    }
227	
228	    private void BuildReferenceHandlingParameters()
229	    {
230	        if (!_builderContext.Configuration.Mapper.UseReferenceHandling)
231	            return;
232	
233	        foreach (var methodMapping in _mappings.MethodMappings)
234	        {
235	            methodMapping.EnableReferenceHandling(_builderContext.Types.Get<IReferenceHandler>());
236	        }
237	    }
238	
239	    private void AddMappingsToDescriptor()
240	    {
241	        // add generated mappings to the mapper
242	        _mapperDescriptor.AddMethodMappings(_mappings.MethodMappings);
243	    }
244	
245	    private void AddAccessorsToDescriptor()
246	    {
247	        _mapperDescriptor.UnsafeAccessors = _unsafeAccessorContext;
248	    }
249	
250	    private void AddUserMapping(IUserMapping mapping, bool ignoreDuplicates, string? name = null)
251	    {
252	        var result = _mappings.AddUserMapping(mapping, name);
253	        if (!ignoreDuplicates && mapping.Default == true && result == MappingCollectionAddResult.NotAddedDuplicated)
254	        {
255	            _diagnostics.ReportDiagnostic(
256	                DiagnosticDescriptors.MultipleDefaultUserMappings,
257	                mapping.Method,
258	                mapping.SourceType.ToDisplayString(),
259	                mapping.TargetType.ToDisplayString()
260	            );
261	        }
262	
263	        _inlineMappings.AddUserMapping(mapping, name);
264	    }
