266	    private void AddUserMappingDiagnostics()
267	    {
268	        foreach (var mapping in _mappings.UsedDuplicatedNonDefaultNonReferencedUserMappings)
269	        {
270	            _diagnostics.ReportDiagnostic(
271	                DiagnosticDescriptors.MultipleUserMappingsWithoutDefault,
272	                mapping.Method,
273	                mapping.SourceType.ToDisplayString(),
274	                mapping.TargetType.ToDisplayString()
