13	
14	/// <summary>
15	/// Represents a mapping which is not a single expression but an entire method.
16	/// </summary>
17	[DebuggerDisplay("{GetType().Name}({SourceType} => {TargetType})")]
18	public abstract class MethodMapping : ITypeMapping, IParameterizedMapping
19	{
20	    protected const string DefaultReferenceHandlerParameterName = "refHandler";
21	    private const string DefaultSourceParameterName = "source";
22	
23	    private const int SourceParameterIndex = 0;
24	    private const int ReferenceHandlerParameterIndex = 1;
25	
26	    private static readonly IEnumerable<SyntaxToken> _privateSyntaxToken = [TrailingSpacedToken(SyntaxKind.PrivateKeyword)];
27	
28	    private static readonly IEnumerable<SyntaxToken> _privateStaticSyntaxToken =
29	    [
30	        TrailingSpacedToken(SyntaxKind.PrivateKeyword),
31	        TrailingSpacedToken(SyntaxKind.StaticKeyword),
32	    ];
33	
34	    private readonly ITypeSymbol _returnType;
35	    private readonly MethodDeclarationSyntax? _methodDeclarationSyntax;
36	
37	    private string? _methodName;
38	
39	    protected MethodMapping(ITypeSymbol sourceType, ITypeSymbol targetType)
40	    {
41	        TargetType = targetType;
42	        SourceParameter = new MethodParameter(SourceParameterIndex, DefaultSourceParameterName, sourceType);
43	        _returnType = targetType;
44	    }
45	
46	    protected MethodMapping(
47	        IMethodSymbol method,
48	        MethodParameter sourceParameter,
49	        MethodParameter? referenceHandlerParameter,
50	        ITypeSymbol targetType
51	    )
52	    {
53	        TargetType = targetType;
54	        SourceParameter = sourceParameter;
55	        Method = method;
56	        IsExtensionMethod = method.IsExtensionMethod;
57	        ReferenceHandlerParameter = referenceHandlerParameter;
58	        _methodDeclarationSyntax = method.DeclaringSyntaxReferences.FirstOrDefault()?.GetSyntax() as MethodDeclarationSyntax;
59	        _methodName = method.Name;
60	        _returnType = method.ReturnsVoid ? method.ReturnType : targetType;
61	    }
62	
63	    public IReadOnlyCollection<MethodParameter> AdditionalSourceParameters { get; init; } = [];
64	
65	    protected IMethodSymbol? Method { get; }
66	
67	    protected bool IsExtensionMethod { get; }
68	
69	    protected string MethodName => _methodName ?? throw new InvalidOperationException();
70	
71	    protected MethodParameter SourceParameter { get; }
72	
73	    protected MethodParameter? ReferenceHandlerParameter { get; private set; }
74	
75	    public ITypeSymbol SourceType => SourceParameter.Type;
76	
77	    public ITypeSymbol TargetType { get; }
78	
79	    public bool IsSynthetic => false;
80	
81	    public virtual IEnumerable<TypeMappingKey> BuildAdditionalMappingKeys(TypeMappingConfiguration config) => [];
82	
83	    public virtual ExpressionSyntax Build(TypeMappingBuildContext ctx) =>
84	        ctx.SyntaxFactory.Invocation(MethodName, ctx.BuildArguments(Method, SourceParameter, ReferenceHandlerParameter));
85	
86	    public virtual MethodDeclarationSyntax BuildMethod(SourceEmitterContext ctx)
87	    {
88	        IReadOnlyDictionary<string, ExpressionSyntax>? additionalParams = null;
89	        if (AdditionalSourceParameters.Count > 0)
90	        {
91	            additionalParams = AdditionalSourceParameters.ToDictionary(
92	                p => p.NormalizedName,
93	                p => (ExpressionSyntax)IdentifierName(p.Name),
94	                StringComparer.OrdinalIgnoreCase
95	            );
96	        }
97	
98	        var typeMappingBuildContext = new TypeMappingBuildContext(
99	            SourceParameter.Name,
100	            ReferenceHandlerParameter?.Name,
101	            ctx.NameBuilder.NewScope(),
102	            ctx.SyntaxFactory,
103	            additionalParams
104	        );
105	
106	        var parameters = BuildParameterList();
107	        ReserveParameterNames(typeMappingBuildContext.NameBuilder, parameters);
108	
109	        var returnType = FullyQualifiedIdentifier(_returnType);
110	        return MethodDeclaration(returnType.AddTrailingSpace(), Identifier(MethodName))
111	            .WithModifiers(TokenList(BuildModifiers(ctx.IsStatic)))
112	            .WithParameterList(parameters)
113	            .WithAttributeLists(BuildAttributes(typeMappingBuildContext))
114	            .WithBody(ctx.SyntaxFactory.Block(BuildBody(typeMappingBuildContext.AddIndentation())));
115	    }
116	
117	    public abstract IEnumerable<StatementSyntax> BuildBody(TypeMappingBuildContext ctx);
118	
119	    internal void SetMethodNameIfNeeded(Func<MethodMapping, string> methodNameBuilder)
120	    {
121	        _methodName ??= methodNameBuilder(this);
122	    }
123	
124	    internal virtual void EnableReferenceHandling(INamedTypeSymbol iReferenceHandlerType)
125	    {
126	        ReferenceHandlerParameter ??= new MethodParameter(
127	            ReferenceHandlerParameterIndex,
128	            DefaultReferenceHandlerParameterName,
129	            iReferenceHandlerType
130	        );
131	    }
132	
133	    protected internal virtual SyntaxList<AttributeListSyntax> BuildAttributes(TypeMappingBuildContext ctx) =>
134	        SingletonList(ctx.SyntaxFactory.GeneratedCodeAttribute());
135	
136	    protected virtual ParameterListSyntax BuildParameterList() =>
137	        ParameterList(IsExtensionMethod, [SourceParameter, ReferenceHandlerParameter, .. AdditionalSourceParameters]);
138	
139	    private IEnumerable<SyntaxToken> BuildModifiers(bool isStatic)
140	    {
141	        // if a syntax is referenced the code written by the user copy all modifiers,
142	        // otherwise only set private and optionally static
143	        if (_methodDeclarationSyntax != null)
144	        {
145	            return _methodDeclarationSyntax.Modifiers.Select(x => TrailingSpacedToken(x.Kind()));
146	        }
147	
148	        return isStatic ? _privateStaticSyntaxToken : _privateSyntaxToken;
149	    }
150	
151	    private void ReserveParameterNames(UniqueNameBuilder nameBuilder, ParameterListSyntax parameters)
152	    {
153	        foreach (var param in parameters.Parameters)
154	        {
155	            nameBuilder.Reserve(param.Identifier.Text);
156	        }
157	    }
158	}
