1	using Riok.Mapperly.Descriptors.Mappings;
2	using Riok.Mapperly.Descriptors.Mappings.MemberMappings;
3	using Riok.Mapperly.Descriptors.Mappings.UserMappings;
4	
5	namespace Riok.Mapperly.Descriptors.MappingBodyBuilders;
6	
7	/// <summary>
8	/// Builds bodies mappings (the body of the mapping methods).
9	/// </summary>
10	public class MappingBodyBuilder(MappingCollection mappings)
11	{
12	    public void BuildMappingBodies(CancellationToken cancellationToken)
13	    {
14	        foreach (var (typeMapping, ctx) in mappings.DequeueMappingsToBuildBody())
15	        {
16	            cancellationToken.ThrowIfCancellationRequested();
17	
18	            switch (typeMapping)
19	            {
20	                case INewInstanceEnumerableMapping mapping:
21	                    EnumerableMappingBodyBuilder.BuildMappingBody(ctx, mapping);
22	                    break;
23	                case IEnumerableMapping mapping:
24	                    EnumerableMappingBodyBuilder.BuildMappingBody(ctx, mapping);
25	                    break;
26	                case NewInstanceObjectMemberMethodMapping mapping:
27	                    NewInstanceObjectMemberMappingBodyBuilder.BuildMappingBody(ctx, mapping);
28	                    break;
29	                case NewInstanceObjectMemberMapping mapping:
30	                    NewInstanceObjectMemberMappingBodyBuilder.BuildMappingBody(ctx, mapping);
31	                    break;
32	                case NewValueTupleExpressionMapping mapping:
33	                    NewValueTupleMappingBodyBuilder.BuildMappingBody(ctx, mapping);
34	                    break;
35	                case NewValueTupleConstructorMapping mapping:
36	                    NewValueTupleMappingBodyBuilder.BuildMappingBody(ctx, mapping);
37	                    break;
38	                case IMemberAssignmentTypeMapping mapping:
39	                    ObjectMemberMappingBodyBuilder.BuildMappingBody(ctx, mapping);
40	                    break;
41	                case UserDefinedNewInstanceMethodMapping mapping:
