1	using System.Diagnostics.CodeAnalysis;
2	using Riok.Mapperly.Descriptors.MappingBodyBuilders.BuilderContext;
3	using Riok.Mapperly.Descriptors.Mappings;
4	using Riok.Mapperly.Descriptors.Mappings.ExistingTarget;
5	using Riok.Mapperly.Descriptors.Mappings.MemberMappings;
6	using Riok.Mapperly.Diagnostics;
7	using Riok.Mapperly.Symbols.Members;
8	
9	namespace Riok.Mapperly.Descriptors.MappingBodyBuilders;
10	
11	/// <summary>
12	/// Mapping body builder for object member mappings.
13	/// </summary>
14	public static class ObjectMemberMappingBodyBuilder
15	{
16	    public static void BuildMappingBody(MappingBuilderContext ctx, IMemberAssignmentTypeMapping mapping)
17	    {
18	        var mappingCtx = new MembersContainerBuilderContext<IMemberAssignmentTypeMapping>(ctx, mapping);
19	        BuildMappingBody(mappingCtx);
20	
21	        // init only members should not result in unmapped diagnostics for existing target mappings
22	        foreach (var initOnlyTargetMember in mappingCtx.EnumerateUnmappedTargetMembers().Where(x => x.IsInitOnly).ToArray())
23	        {
24	            mappingCtx.SetTargetMemberMapped(initOnlyTargetMember);
25	        }
26	
27	        // do not report "no member mapping" for existing target mappings
28	        mappingCtx.MappingAdded();
29	
30	        mappingCtx.AddDiagnostics(false);
31	    }
32	
33	    public static void BuildMappingBody(IMembersContainerBuilderContext<IMemberAssignmentTypeMapping> ctx)
34	    {
35	        foreach (var targetMember in ctx.EnumerateUnmappedOrConfiguredTargetMembers())
36	        {
37	            foreach (var memberMappingInfo in ctx.MatchMembers(targetMember))
38	            {
39	                BuildMemberAssignmentMapping(ctx, memberMappingInfo);
40	            }
41	        }
42	    }
43	
44	    [SuppressMessage("Meziantou.Analyzer", "MA0051:MethodIsTooLong")]
45	    public static bool ValidateMappingSpecification(
46	        IMembersBuilderContext<IMapping> ctx,
47	        MemberMappingInfo memberInfo,
48	        bool allowInitOnlyMember = false
49	    )
50	    {
51	        var sourceMemberPath = memberInfo.SourceMember;
52	        var targetMemberPath = memberInfo.TargetMember;
53	
54	        // the target member path is readonly or not accessible
55	        if (!targetMemberPath.Member.CanSet)
56	        {
57	            // If the mapping is matched automatically without any configuration
58	            // mark both members as mapped,
59	            // as the "CannotMapToReadOnlyMember" diagnostic should be informative.
60	            // Also, an additional diagnostic may not even be expected here:
61	            // for example, if the source and target contain the same computed read-only member.
62	            if (memberInfo.IsAutoMatch && sourceMemberPath?.Type == SourceMemberType.Member)
63	            {
64	                ctx.SetMembersMapped(memberInfo);
65	                return false;
66	            }
67	
68	            ctx.BuilderContext.ReportDiagnostic(
69	                DiagnosticDescriptors.CannotMapToReadOnlyMember,
70	                memberInfo.DescribeSource(),
71	                targetMemberPath.ToDisplayString(includeMemberType: false)
72	            );
73	            return false;
74	        }
75	
76	        // cannot access non public member in initializer
77	        if (allowInitOnlyMember && !targetMemberPath.Member.CanSetDirectly)
78	        {
79	            ctx.BuilderContext.ReportDiagnostic(
80	                DiagnosticDescriptors.CannotMapToReadOnlyMember,
81	                memberInfo.DescribeSource(),
82	                targetMemberPath.ToDisplayString(includeMemberType: false)
83	            );
84	            return false;
85	        }
86	
87	        // a target member path part is write only or not accessible
88	        // an expressions target member path is only accessible with unsafe access
89	        if (
90	            targetMemberPath.ObjectPath.Any(p => !p.CanGet)
91	            || (ctx.BuilderContext.IsExpression && targetMemberPath.ObjectPath.Any(p => !p.CanGetDirectly))
92	        )
93	        {
94	            ctx.BuilderContext.ReportDiagnostic(
95	                DiagnosticDescriptors.CannotMapToWriteOnlyMemberPath,
96	                memberInfo.DescribeSource(),
97	                targetMemberPath.ToDisplayString()
98	            );
99	            return false;
100	        }
101	
102	        // cannot assign to intermediate value type, error CS1612
103	        // invalid mapping a value type has a property set
104	        if (!ValidateStructModification(ctx, memberInfo))
105	            return false;
106	
107	        // a target member path part is init only
108	        var noInitOnlyPath = allowInitOnlyMember ? targetMemberPath.ObjectPath : targetMemberPath.Path;
109	        if (noInitOnlyPath.Any(p => p.IsInitOnly))
110	        {
111	            if (ctx.HasDuplicatedMemberConfig(targetMemberPath))
112	            {
113	                ctx.BuilderContext.ReportDiagnostic(
114	                    DiagnosticDescriptors.MultipleConfigurationsForTargetMember,
115	                    ctx.Mapping.TargetType.ToDisplayString(),
116	                    targetMemberPath.ToDisplayString(includeMemberType: false, includeRootType: false)
117	                );
118	            }
119	            else
120	            {
121	                ctx.BuilderContext.ReportDiagnostic(
122	                    DiagnosticDescriptors.CannotMapToInitOnlyMemberPath,
123	                    memberInfo.DescribeSource(),
124	                    targetMemberPath.ToDisplayString(includeMemberType: false)
125	                );
126	            }
127	            return false;
128	        }
129	
130	        // a source member path is write only or not accessible
131	        // an expressions source member path is only accessible with unsafe access
132	        if (
133	            sourceMemberPath != null
134	            && (
135	                sourceMemberPath.MemberPath.Path.Any(p => !p.CanGet)
136	                || (ctx.BuilderContext.IsExpression && sourceMemberPath.MemberPath.Path.Any(p => !p.CanGetDirectly))
137	            )
138	        )
139	        {
140	            ctx.BuilderContext.ReportDiagnostic(
141	                DiagnosticDescriptors.CannotMapFromWriteOnlyMember,
142	                sourceMemberPath.MemberPath.ToDisplayString(),
143	                targetMemberPath.ToDisplayString()
144	            );
145	            return false;
146	        }
147	
148	        return true;
149	    }
150	
151	    private static bool ValidateStructModification(IMembersBuilderContext<IMapping> ctx, MemberMappingInfo memberInfo)
152	    {
153	        if (memberInfo.TargetMember.Path.Count <= 1)
154	            return true;
155	
156	        // iterate backwards, if a reference type property is found then path is valid
157	        // if a value type property is found then invalid, a temporary struct is being modified
158	        for (var i = memberInfo.TargetMember.Path.Count - 2; i >= 0; i--)
159	        {
160	            var member = memberInfo.TargetMember.Path[i];
161	            if (member is PropertyMember { Type: { IsValueType: true, IsRefLikeType: false } })
162	            {
163	                ctx.BuilderContext.ReportDiagnostic(
164	                    DiagnosticDescriptors.CannotMapToTemporarySourceMember,
165	                    memberInfo.DescribeSource(),
166	                    memberInfo.TargetMember.ToDisplayString(),
167	                    member.Type,
168	                    member.Name
169	                );
170	                return false;
171	            }
172	
173	            if (member is PropertyMember { Type.IsReferenceType: true })
174	                break;
175	        }
176	
177	        return true;
178	    }
179	
180	    private static void BuildMemberAssignmentMapping(
181	        IMembersContainerBuilderContext<IMemberAssignmentTypeMapping> ctx,
182	        MemberMappingInfo memberMappingInfo
183	    )
184	    {
185	        // consume member configs
186	        // to ensure no further mappings are created for these configurations,
187	        // even if a mapping validation fails
188	        ctx.ConsumeMemberConfigs(memberMappingInfo);
189	
190	        if (TryAddExistingTargetMapping(ctx, memberMappingInfo))
191	            return;
192	
193	        if (!ValidateMappingSpecification(ctx, memberMappingInfo))
194	            return;
195	
196	        if (!MemberMappingBuilder.TryBuildContainerAssignment(ctx, memberMappingInfo, out var requiresNullHandling, out var mapping))
197	            return;
198	
199	        if (requiresNullHandling)
200	        {
201	            ctx.AddNullDelegateMemberAssignmentMapping(mapping);
202	        }
203	        else
204	        {
205	            ctx.AddMemberAssignmentMapping(mapping);
206	        }
207	    }
208	
209	    private static bool TryAddExistingTargetMapping(
210	        IMembersContainerBuilderContext<IMemberAssignmentTypeMapping> ctx,
211	        MemberMappingInfo memberMappingInfo
212	    )
213	    {
214	        // can only map with an existing target from a source member
215	        if (memberMappingInfo.SourceMember == null)
216	            return false;
217	
218	        var sourceMemberPath = memberMappingInfo.SourceMember;
219	        var targetMemberPath = memberMappingInfo.TargetMember;
220	
221	        // if a named existing target mapping exists, we are always good.
222	        // if the member is readonly
223	        // and the target and source path is readable,
224	        // we also try to create an existing target mapping
225	        if (
226	            !HasExistingTargetNamedMapping(ctx, memberMappingInfo)
227	            && (
228	                targetMemberPath.Member is { CanSet: true, IsInitOnly: false }
229	                || !targetMemberPath.Path.All(op => op.CanGet)
230	                || !sourceMemberPath.MemberPath.Path.All(op => op.CanGet)
231	            )
232	        )
233	        {
234	            return false;
235	        }
236	
237	        var existingTargetMapping = ctx.BuilderContext.FindOrBuildExistingTargetMapping(memberMappingInfo.ToTypeMappingKey());
238	        if (existingTargetMapping is null)
239	            return false;
240	
241	        if (HasCircularReference(ctx, existingTargetMapping, targetMemberPath))
242	        {
243	            ctx.BuilderContext.ReportDiagnostic(DiagnosticDescriptors.CircularMappingWithoutSetter, targetMemberPath.FullName);
244	            return false;
245	        }
246	
247	        var sourceMemberGetter = sourceMemberPath.MemberPath.BuildGetter(ctx.BuilderContext);
248	        var targetMemberGetter = targetMemberPath.BuildGetter(ctx.BuilderContext);
249	        var memberMapping = new MemberExistingTargetMapping(
250	            existingTargetMapping,
251	            sourceMemberGetter,
252	            targetMemberGetter,
253	            memberMappingInfo
254	        );
255	        ctx.AddMemberAssignmentMapping(memberMapping);
256	        return true;
257	    }
258	
259	    private static bool HasExistingTargetNamedMapping(
260	        IMembersContainerBuilderContext<IMemberAssignmentTypeMapping> ctx,
261	        MemberMappingInfo memberMappingInfo
262	    )
263	    {
264	        if (memberMappingInfo.Configuration?.Use is null)
265	            return false;
266	
267	        // check if named mapping defined as existing target mapping.
268	        // it could be defined as new instance mapping.
269	        var mapping = ctx.BuilderContext.FindExistingTargetNamedMapping(memberMappingInfo.Configuration.Use.FullName);
270	        return mapping != null;
271	    }
272	
273	    private static bool HasCircularReference(
274	        IMembersContainerBuilderContext<IMemberAssignmentTypeMapping> ctx,
275	        IExistingTargetMapping existingTargetMapping,
276	        NonEmptyMemberPath targetMemberPath
277	    )
278	    {
279	        return !targetMemberPath.Path[^1].CanSet
280	            && existingTargetMapping is IMemberAssignmentMappingContainer existingContainer
281	            && ctx.Mapping is IMemberAssignmentMappingContainer baseMapping
282	            && existingContainer.HasMemberMappingContainer(baseMapping);
