using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Riok.Mapperly.Emit.Syntax;
using Riok.Mapperly.Helpers;
using Riok.Mapperly.Symbols;
using static Microsoft.CodeAnalysis.CSharp.SyntaxFactory;
using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;

namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;

/// <summary>
/// Represents a generic mapping method on the mapper which is implemented by the user.
/// </summary>
public class UserImplementedGenericTypeMapping(
    string? receiver,
    IMethodSymbol method,
    bool? isDefault,
    MethodParameter sourceParameter,
    ITypeSymbol targetType,
    MethodParameter? referenceHandlerParameter,
    bool isExternal,
    UserImplementedMethodMapping.TargetNullability targetNullability,
    GenericTypeChecker.GenericTypeMapping genericTypeMapping
) : NewInstanceMapping(sourceParameter.Type, targetType), INewInstanceUserMapping, IParameterizedMapping
{
    public IMethodSymbol Method { get; } = method;

    public bool? Default { get; } = isDefault;

    public bool IsExternal { get; } = isExternal;

    public IReadOnlyCollection<MethodParameter> AdditionalSourceParameters { get; } =
        method
            .Parameters.Where(p =>
                p.Ordinal != sourceParameter.Ordinal
                && (referenceHandlerParameter is null || p.Ordinal != referenceHandlerParameter.Value.Ordinal)
            )
            .Select(p => new MethodParameter(p, p.Type))
            .ToList();

    public override IEnumerable<TypeMappingKey> BuildAdditionalMappingKeys(TypeMappingConfiguration config)
    {
        var keys = base.BuildAdditionalMappingKeys(config);
        switch (targetNullability)
        {
            case UserImplementedMethodMapping.TargetNullability.NeverNull when TargetType.IsNullable():
                keys = keys.Append(new TypeMappingKey(SourceType, TargetType.NonNullable()));
                goto case UserImplementedMethodMapping.TargetNullability.NotNullIfSourceNotNull;
            case UserImplementedMethodMapping.TargetNullability.NotNullIfSourceNotNull:
                keys = keys.Append(new TypeMappingKey(SourceType.NonNullable(), TargetType.NonNullable()));
                break;
        }

        return keys;
    }

    public override ExpressionSyntax Build(TypeMappingBuildContext ctx)
    {
        var methodExpression = BuildMethodExpression();
        return ctx.SyntaxFactory.Invocation(
            methodExpression,
            ctx.BuildArguments(Method, sourceParameter, referenceHandlerParameter)
        );
    }

    private ExpressionSyntax BuildMethodExpression()
    {
        var method = GenericName(Method.Name)
            .WithTypeArgumentList(SyntaxFactoryHelper.TypeArgumentList(BuildTypeArguments()));

        if (Method.ReceiverType?.TypeKind == TypeKind.Interface)
        {
            var castedReceiver = CastExpression(
                FullyQualifiedIdentifier(Method.ReceiverType!),
                receiver == null ? ThisExpression() : IdentifierName(receiver)
            );
            return MemberAccess(ParenthesizedExpression(castedReceiver), method);
        }

        return receiver == null ? method : MemberAccess(IdentifierName(receiver), method);
    }

    private IEnumerable<TypeSyntax> BuildTypeArguments() => Method.TypeParameters.Select(BuildTypeArgument);

    private TypeSyntax BuildTypeArgument(ITypeParameterSymbol typeParameter)
    {
        var typeArg = genericTypeMapping[typeParameter];
        return NonNullableIdentifier(typeArg);
    }
}

